<script>
  import { onMount } from 'svelte';
  import { Activity, BarChart3, Check, ClipboardCheck, RefreshCw, Sparkles, TriangleAlert, XCircle } from 'lucide-svelte';
  let data=$state(null),plans=$state([]),loading=$state(true),message=$state(''),error=$state('');
  onMount(load);
  async function load(){loading=true;error='';const[e,u]=await Promise.all([fetch('/api/evaluation'),fetch('/api/upgrades')]);const d=await e.json(),p=await u.json();if(e.ok)data=d;else error=d.error;plans=p.plans??[];loading=false}
  async function post(body){loading=true;const r=await fetch(body.proposalId||body.id?'/api/upgrades':'/api/evaluation',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(body)});const d=await r.json();if(!r.ok)error=d.error;await load();return d}
  async function generate(){const d=await post({operation:'generate'});message=`${d.proposals?.length??0} new proposal(s) created`}
  async function decide(id,status){await fetch('/api/evaluation',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({operation:'decide',id,status})});message=`Proposal ${status}`;await load()}
</script>

<svelte:head><title>Evaluation · J.A.R.V.I.S.</title></svelte:head>
<div class="page">
  <header class="hero"><div class="hero-icon"><BarChart3 size={22}/></div><div><span class="eyebrow">SYSTEM GOVERNANCE</span><h1>Capability Evaluation</h1><p>See what works, understand failures, and approve improvements before anything changes.</p></div><button onclick={load} disabled={loading}><RefreshCw size={15}/>{loading?'Checking…':'Refresh'}</button></header>
  <section class="workflow" aria-label="Improvement workflow"><div class="active"><b>1</b><span><strong>Observe</strong><small>Collect outcomes</small></span></div><i></i><div><b>2</b><span><strong>Propose</strong><small>Use evidence</small></span></div><i></i><div><b>3</b><span><strong>Approve</strong><small>Human decision</small></span></div><i></i><div><b>4</b><span><strong>Validate</strong><small>Block regressions</small></span></div></section>
  {#if error}<div class="notice error"><TriangleAlert size={16}/>{error}</div>{/if}{#if message}<div class="notice success"><Check size={16}/>{message}</div>{/if}
  {#if data}
    <section class="stats"><article><span>Recorded runs</span><strong>{data.summary.totalExecutions}</strong><small>Tools and models</small></article><article><span>Reliability</span><strong>{data.summary.successRate}%</strong><small>Successful executions</small></article><article><span>Model failures</span><strong>{data.summary.modelFailures}<em> / {data.summary.modelRuns}</em></strong><small>Review provider health</small></article><article><span>Needs review</span><strong>{data.summary.proposalsOpen}</strong><small>Open proposals</small></article></section>
    <section class="grid"><article class="card"><div class="card-head"><div><span>PERFORMANCE</span><h2>Capability health</h2></div><Activity size={18}/></div>{#each data.capabilities as item(item.capability)}<div class="row"><div><strong>{item.capability}</strong><small>{item.kind} · {item.runs} runs · {item.averageDurationMs}ms average</small></div><span class:bad={item.successRate<80}>{item.successRate}%</span></div>{/each}{#if !data.capabilities.length}<div class="empty">Use tools or chat to begin collecting reliability data.</div>{/if}</article><article class="card"><div class="card-head"><div><span>ATTENTION</span><h2>Recent failures</h2></div><TriangleAlert size={18}/></div>{#each data.recentFailures as item(item.id)}<div class="failure"><TriangleAlert size={15}/><div><strong>{item.capability}</strong><small>{item.error}</small></div></div>{/each}{#if !data.recentFailures.length}<div class="empty good">No recorded capability failures.</div>{/if}</article></section>
    <section class="card proposals"><div class="card-head"><div><span>HUMAN REVIEW</span><h2>Improvement proposals</h2><p>J.A.R.V.I.S. suggests a direction; you decide whether it deserves a validated plan.</p></div><button class="primary" onclick={generate}><Sparkles size={15}/>Analyze evidence</button></div>{#each data.proposals as proposal(proposal.id)}<article><div class="proposal-main"><div class="tags"><span>{proposal.risk} risk</span><span>{proposal.status}</span><code>{proposal.target}</code></div><h3>{proposal.title}</h3><p>{proposal.rationale}</p><details><summary>Why is this suggested?</summary>{#each proposal.evidence as evidence(evidence)}<code>{evidence}</code>{/each}</details></div><div class="actions">{#if proposal.status==='proposed'}<button class="primary" onclick={()=>decide(proposal.id,'approved')}><Check size={14}/>Approve direction</button><button onclick={()=>decide(proposal.id,'dismissed')}><XCircle size={14}/>Dismiss</button>{:else if proposal.status==='approved'&&!plans.some(plan=>plan.proposalId===proposal.id)}<button class="primary" onclick={()=>post({operation:'prepare',proposalId:proposal.id})}><ClipboardCheck size={14}/>Prepare validated plan</button>{/if}</div></article>{/each}{#if !data.proposals.length}<div class="empty">No proposals yet. Analyze evidence after the system has enough execution history.</div>{/if}</section>
    <section class="card"><div class="card-head"><div><span>SAFE UPGRADES</span><h2>Validation plans</h2><p>Only fixed checks run here. No code is changed automatically.</p></div></div>{#each plans as plan(plan.id)}<div class="plan"><div><h3>{plan.title}</h3><span class="status">{plan.status}</span><p>{plan.steps.join(' → ')}</p>{#each plan.validation as gate(gate.command)}<code class:pass={gate.ok}>{gate.ok?'PASS':'FAIL'} · {gate.command} · {gate.durationMs}ms</code>{/each}</div>{#if plan.status==='ready'}<button onclick={()=>post({operation:'verify',id:plan.id})}><Check size={14}/>Run gates again</button>{/if}</div>{/each}{#if !plans.length}<div class="empty">Approve a proposal, then prepare it to run baseline validation.</div>{/if}</section>
  {/if}
</div>

<style>
  .page{max-width:1200px;padding:32px;display:grid;gap:20px;color:var(--text-primary)}.hero{display:flex;align-items:center;gap:14px}.hero>div:nth-child(2){flex:1}.hero-icon{width:44px;height:44px;display:grid;place-items:center;border:1px solid var(--surface-border);border-radius:12px;background:var(--surface-card)}h1{font-size:28px;line-height:1.1;margin:3px 0 6px}.hero p,.card-head p{margin:0;color:var(--text-secondary);font-size:13px}.eyebrow,.card-head span{font-size:10px;letter-spacing:.12em;color:var(--text-tertiary);font-weight:700}button{display:inline-flex;align-items:center;justify-content:center;gap:7px;padding:9px 12px;border:1px solid var(--surface-border);border-radius:8px;background:var(--surface-card);color:var(--text-primary);font-size:12px;font-weight:600;cursor:pointer}.primary{background:var(--text-primary);color:var(--surface-bg)}.workflow{display:flex;align-items:center;padding:14px 18px;border:1px solid var(--surface-border);border-radius:12px;background:var(--surface-card)}.workflow>div{display:flex;align-items:center;gap:9px}.workflow b{width:26px;height:26px;border-radius:50%;display:grid;place-items:center;border:1px solid var(--surface-border);font-size:11px}.workflow .active b{background:var(--text-primary);color:var(--surface-bg)}.workflow span{display:grid}.workflow strong{font-size:12px}.workflow small{font-size:10px;color:var(--text-tertiary)}.workflow i{height:1px;flex:1;background:var(--surface-border);margin:0 14px}.notice{display:flex;gap:8px;align-items:center;padding:10px 12px;border-radius:8px;font-size:12px}.notice.error{background:rgba(239,68,68,.08);color:#ef4444}.notice.success{background:rgba(34,197,94,.08);color:#22c55e}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.stats article,.card{border:1px solid var(--surface-border);background:var(--surface-card);border-radius:12px;padding:18px}.stats article{display:grid;gap:3px}.stats span,.stats small{font-size:11px;color:var(--text-secondary)}.stats strong{font-size:28px}.stats em{font-size:14px;color:var(--text-tertiary);font-style:normal}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.card-head{display:flex;align-items:flex-start;justify-content:space-between;gap:16px;margin-bottom:12px}.card-head h2{font-size:16px;margin:3px 0}.row,.failure{display:flex;align-items:center;gap:10px;padding:11px 0;border-top:1px solid var(--surface-border-subtle)}.row>div,.failure>div{display:grid;flex:1}.row strong,.failure strong{font-size:12px}.row small,.failure small{font-size:10px;color:var(--text-tertiary)}.row>span{font-size:12px;font-weight:700;color:#22c55e}.row>span.bad{color:#ef4444}.empty{padding:24px;text-align:center;color:var(--text-tertiary);font-size:12px;border:1px dashed var(--surface-border);border-radius:8px}.empty.good{color:#22c55e}.proposals>article,.plan{display:flex;align-items:flex-start;gap:16px;padding:16px 0;border-top:1px solid var(--surface-border-subtle)}.proposal-main,.plan>div{flex:1}.tags{display:flex;align-items:center;gap:6px}.tags span,.status{font-size:9px;text-transform:uppercase;padding:3px 6px;border:1px solid var(--surface-border);border-radius:10px;color:var(--text-secondary)}.tags code{font-size:10px;color:var(--text-tertiary)}h3{font-size:14px;margin:8px 0 4px}.proposal-main p,.plan p{font-size:12px;color:var(--text-secondary);margin:0 0 8px}details{font-size:11px;color:var(--text-secondary)}details code,.plan code{display:block;padding:6px 8px;margin-top:5px;border-radius:5px;background:var(--surface-bg);font-size:10px}.plan code.pass{color:#22c55e}.actions{display:flex;gap:7px;flex-wrap:wrap}@media(max-width:800px){.page{padding:18px}.hero{flex-wrap:wrap}.workflow span{display:none}.stats{grid-template-columns:1fr 1fr}.grid{grid-template-columns:1fr}.proposals>article,.plan{flex-direction:column}}
</style>
